     1→import { useState, useEffect } from "react";
     2→import { Layout } from "@/components/layout";
     3→import { useGetSettings, useUpdateSetting } from "@workspace/api-client-react";
     4→import { PlatformIcon } from "@/components/platform-icon";
     5→import { Button } from "@/components/ui/button";
     6→import { useToast } from "@/hooks/use-toast";
     7→import { Loader2, Save } from "lucide-react";
     8→import { motion } from "framer-motion";
     9→
    10→export default function Settings() {
    11→  const { data: settings, isLoading } = useGetSettings();
    12→  const updateMutation = useUpdateSetting();
    13→  const { toast } = useToast();
    14→
    15→  const [localSettings, setLocalSettings] = useState<Record<string, any>>({});
    16→  const [savingPlatform, setSavingPlatform] = useState<string | null>(null);
    17→
    18→  useEffect(() => {
    19→    if (settings) {
    20→      const mapped: Record<string, any> = {};
    21→      settings.forEach(s => {
    22→        mapped[s.platformId] = {
    23→          instructions: s.instructions,
    24→          audience: s.audience,
    25→          language: s.language
    26→        };
    27→      });
    28→      setLocalSettings(mapped);
    29→    }
    30→  }, [settings]);
    31→
    32→  const handleChange = (platformId: string, field: string, value: string) => {
    33→    setLocalSettings(prev => ({
    34→      ...prev,
    35→      [platformId]: {
    36→        ...prev[platformId],
    37→        [field]: value
    38→      }
    39→    }));
    40→  };
    41→
    42→  const handleSave = async (platformId: string) => {
    43→    setSavingPlatform(platformId);
    44→    try {
    45→      await updateMutation.mutateAsync({
    46→        platformId,
    47→        data: localSettings[platformId]
    48→      });
    49→      toast({ title: "Settings Saved", description: `${platformId} configuration updated.` });
    50→    } catch (e) {
    51→      toast({ variant: "destructive", title: "Error", description: "Failed to save settings." });
    52→    } finally {
    53→      setSavingPlatform(null);
    54→    }
    55→  };
    56→
    57→  if (isLoading) {
    58→    return (
    59→      <Layout>
    60→        <div className="flex items-center justify-center h-64">
    61→          <Loader2 className="w-8 h-8 text-primary animate-spin" />
    62→        </div>
    63→      </Layout>
    64→    );
    65→  }
    66→
    67→  const platforms = ['instagram', 'facebook', 'substack', 'x', 'bluesky'];
    68→
    69→  return (
    70→    <Layout>
    71→      <div className="mb-10">
    72→        <h1 className="text-4xl font-serif font-bold text-foreground mb-4">Platform Configuration</h1>
    73→        <p className="text-muted-foreground text-lg max-w-2xl">
    74→          Define the global default tone, instructions, and audience for each social channel. These defaults apply to all new caption generations.
    75→        </p>
    76→      </div>
    77→
    78→      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
    79→        {platforms.map((platform, idx) => {
    80→          const config = localSettings[platform] || { instructions: '', audience: '', language: 'English' };
    81→          const isSaving = savingPlatform === platform;
    82→
    83→          return (
    84→            <motion.div 
    85→              key={platform}
    86→              initial={{ opacity: 0, y: 20 }}
    87→              animate={{ opacity: 1, y: 0 }}
    88→              transition={{ delay: idx * 0.1 }}
    89→              className="glass-panel rounded-2xl p-6 md:p-8 flex flex-col gap-6"
    90→            >
    91→              <div className="flex items-center justify-between border-b border-white/10 pb-4">
    92→                <div className="flex items-center gap-3">
    93→                  <PlatformIcon platform={platform} className="text-2xl" />
    94→                  <h2 className="text-xl font-serif font-bold capitalize">{platform}</h2>
    95→                </div>
    96→                <select 
    97→                  value={config.language}
    98→                  onChange={(e) => handleChange(platform, 'language', e.target.value)}
    99→                  className="bg-black/30 border border-white/10 rounded-lg px-3 py-1.5 text-sm text-foreground focus:outline-none focus:border-primary"
   100→                >
   101→                  <option value="English">English</option>
   102→                  <option value="Arabic">Arabic</option>
   103→                  <option value="French">French</option>
   104→                  <option value="Spanish">Spanish</option>
   105→                  <option value="Italian">Italian</option>
   106→                </select>
   107→              </div>
   108→
   109→              <div className="space-y-4 flex-1">
   110→                <div>
   111→                  <label className="block text-xs font-semibold text-muted-foreground uppercase tracking-widest mb-2">
   112→                    System Instructions
   113→                  </label>
   114→                  <textarea
   115→                    value={config.instructions}
   116→                    onChange={(e) => handleChange(platform, 'instructions', e.target.value)}
   117→                    className="w-full h-28 bg-black/20 border border-white/5 rounded-xl p-4 text-sm text-foreground focus:outline-none focus:border-primary/50 resize-none font-sans"
   118→                    placeholder="E.g., Maintain an authoritative tone, use bullet points..."
   119→                  />
   120→                </div>
   121→                <div>
   122→                  <label className="block text-xs font-semibold text-muted-foreground uppercase tracking-widest mb-2">
   123→                    Target Audience
   124→                  </label>
   125→                  <input
   126→                    type="text"
   127→                    value={config.audience}
   128→                    onChange={(e) => handleChange(platform, 'audience', e.target.value)}
   129→                    className="w-full bg-black/20 border border-white/5 rounded-xl px-4 py-3 text-sm text-foreground focus:outline-none focus:border-primary/50 font-sans"
   130→                    placeholder="E.g., Policy makers, general public..."
   131→                  />
   132→                </div>
   133→              </div>
   134→
   135→              <div className="pt-2">
   136→                <Button 
   137→                  onClick={() => handleSave(platform)} 
   138→                  disabled={isSaving}
   139→                  className="w-full gap-2"
   140→                >
   141→                  {isSaving ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4" />}
   142→                  Save {platform} Defaults
   143→                </Button>
   144→              </div>
   145→            </motion.div>
   146→          );
   147→        })}
   148→      </div>
   149→    </Layout>
   150→  );
   151→}
