     3→export function PlatformIcon({ platform, className }: { platform: string, className?: string }) {
     4→  const p = platform.toLowerCase();
     5→  let emoji = "📱";
     6→  
     7→  switch(p) {
     8→    case 'instagram': emoji = "📸"; break;
     9→    case 'facebook': emoji = "👥"; break;
    10→    case 'substack': emoji = "📧"; break;
    11→    case 'x': emoji = "𝕏"; break;
    12→    case 'bluesky': emoji = "🦋"; break;
    13→  }
    14→
    15→  return (
    16→    <span className={cn("inline-flex items-center justify-center", className)}>
    17→      {emoji}
    18→    </span>
    19→  );
    20→}
