     1→import { Router, type IRouter } from "express";
     2→import Anthropic from "@anthropic-ai/sdk";
     3→import {
     4→  GenerateCaptionsBody,
     5→  GenerateCaptionsResponse,
     6→  RefineCaptionBody,
     7→  RefineCaptionResponse,
     8→  RewriteCaptionBody,
     9→  RewriteCaptionResponse,
    10→  UploadImageBody,
    11→  UploadImageResponse,
    12→} from "@workspace/api-zod";
    13→import { requireAuth } from "../lib/auth.js";
    14→
    15→const router: IRouter = Router();
    16→
    17→function getClient(): Anthropic {
    18→  return new Anthropic({ apiKey: process.env.ANTHROPIC_API_KEY });
    19→}
    20→
    21→const SYSTEM_PROMPT = `You are DiploCaption, an expert social media writer specializing in geopolitical, historical, and diplomatic content. You work for DiploMaps, a media brand that publishes analytical maps about world affairs, history, and international relations.
    22→
    23→Your voice is: neutral and journalistic, analytically rigorous, and accessible to educated general audiences. You never sensationalize. You ground captions in facts visible in or implied by the map.
    24→
    25→You will receive:
    26→1. An image of a map
    27→2. The map type (geopolitical / historical / data-infographic / other)
    28→3. Optional context notes from the author
    29→4. Per-platform instructions and audience descriptions
    30→
    31→Your task: generate one caption per platform, each optimized for that platform's format, audience, and norms. Return your response as a valid JSON object with keys: instagram, facebook, substack, x, bluesky.`;
    32→
    33→function buildUserPrompt(
    34→  mapType: string,
    35→  contextNotes: string | null | undefined,
    36→  overrides: {
    37→    instagram: { instructions: string; audience: string };
    38→    facebook: { instructions: string; audience: string };
    39→    substack: { instructions: string; audience: string };
    40→    x: { instructions: string; audience: string };
    41→    bluesky: { instructions: string; audience: string };
    42→  }
    43→): string {
    44→  return `Map type: ${mapType}
    45→
    46→Author's additional context: ${contextNotes || "None provided"}
    47→
    48→Generate captions for the following platforms:
    49→
    50→INSTAGRAM
    51→Instructions: ${overrides.instagram.instructions}
    52→Audience: ${overrides.instagram.audience}
    53→Format: Engaging caption optimized for Instagram. Use line breaks. Include 3–5 hashtags only if highly relevant to the content.
    54→
    55→FACEBOOK
    56→Instructions: ${overrides.facebook.instructions}
    57→Audience: ${overrides.facebook.audience}
    58→Format: Conversational and informative. Can be slightly longer than Instagram. Hashtags only if relevant.
    59→
    60→SUBSTACK
    61→Instructions: ${overrides.substack.instructions}
    62→Audience: ${overrides.substack.audience}
    63→Format: Short introductory paragraph suitable for a Substack newsletter post or note. No hashtags.
    64→
    65→X (TWITTER)
    66→Instructions: ${overrides.x.instructions}
    67→Audience: ${overrides.x.audience}
    68→Format: Concise, maximum 280 characters. Punchy. No hashtags unless essential.
    69→
    70→BLUESKY
    71→Instructions: ${overrides.bluesky.instructions}
    72→Audience: ${overrides.bluesky.audience}
    73→Format: Similar to X but max 300 characters. Thoughtful and direct. Hashtags only if very relevant.
    74→
    75→Return only a valid JSON object. No preamble, no markdown formatting, no explanation.`;
    76→}
    77→
    78→router.post("/captions/generate", requireAuth, async (req, res): Promise<void> => {
    79→  const parsed = GenerateCaptionsBody.safeParse(req.body);
    80→  if (!parsed.success) {
    81→    res.status(400).json({ error: parsed.error.message });
    82→    return;
    83→  }
    84→
    85→  const { imageData, imageMediaType, mapType, contextNotes, platformOverrides } = parsed.data;
    86→
    87→  const client = getClient();
    88→  const userPrompt = buildUserPrompt(mapType, contextNotes, platformOverrides);
    89→
    90→  let response;
    91→  try {
    92→    response = await client.messages.create({
    93→      model: "claude-sonnet-4-6",
    94→      max_tokens: 2048,
    95→      system: SYSTEM_PROMPT,
    96→      messages: [
    97→        {
    98→          role: "user",
    99→          content: [
   100→            {
   101→              type: "image",
   102→              source: {
   103→                type: "base64",
   104→                media_type: imageMediaType as "image/jpeg" | "image/png" | "image/gif" | "image/webp",
   105→                data: imageData,
   106→              },
   107→            },
   108→            {
   109→              type: "text",
   110→              text: userPrompt,
   111→            },
   112→          ],
   113→        },
   114→      ],
   115→    });
   116→  } catch (e) {
   117→    console.error("[captions/generate] Anthropic API error:", e);
   118→    const message = e instanceof Error ? e.message : "Unknown error";
   119→    res.status(500).json({ error: "AI service error", detail: message });
   120→    return;
   121→  }
   122→
   123→  const textContent = response.content.find((c) => c.type === "text");
   124→  if (!textContent || textContent.type !== "text") {
   125→    res.status(500).json({ error: "No text response from AI" });
   126→    return;
   127→  }
   128→
   129→  let captions: Record<string, string>;
   130→  try {
   131→    const rawText = textContent.text.trim();
   132→    const jsonMatch = rawText.match(/\{[\s\S]*\}/);
   133→    captions = JSON.parse(jsonMatch ? jsonMatch[0] : rawText);
   134→  } catch {
   135→    res.status(500).json({ error: "Failed to parse AI response as JSON" });
   136→    return;
   137→  }
   138→
   139→  res.json(GenerateCaptionsResponse.parse(captions));
   140→});
