   142→router.post("/captions/refine", requireAuth, async (req, res): Promise<void> => {
   143→  const parsed = RefineCaptionBody.safeParse(req.body);
   144→  if (!parsed.success) {
   145→    res.status(400).json({ error: parsed.error.message });
   146→    return;
   147→  }
   148→
   149→  const { platform, currentCaption, instruction } = parsed.data;
   150→
   151→  const client = getClient();
   152→  const prompt = `Here is the current caption for ${platform}:
   153→
   154→"${currentCaption}"
   155→
   156→The user's instruction: "${instruction}"
   157→
   158→Rewrite the caption applying the instruction while preserving the factual content, overall structure, and the DiploMaps voice (neutral, analytical, accessible). Return only the new caption text, no explanation.`;
   159→
   160→  let response;
   161→  try {
   162→    response = await client.messages.create({
   163→      model: "claude-sonnet-4-6",
   164→      max_tokens: 1024,
   165→      messages: [{ role: "user", content: prompt }],
   166→    });
   167→  } catch (e) {
   168→    console.error("[captions/refine] Anthropic API error:", e);
   169→    const message = e instanceof Error ? e.message : "Unknown error";
   170→    res.status(500).json({ error: "AI service error", detail: message });
   171→    return;
   172→  }
   173→
   174→  const textContent = response.content.find((c) => c.type === "text");
   175→  if (!textContent || textContent.type !== "text") {
   176→    res.status(500).json({ error: "No text response from AI" });
   177→    return;
   178→  }
   179→
   180→  res.json(RefineCaptionResponse.parse({ caption: textContent.text.trim() }));
   181→});
