   183→router.post("/captions/rewrite", requireAuth, async (req, res): Promise<void> => {
   184→  const parsed = RewriteCaptionBody.safeParse(req.body);
   185→  if (!parsed.success) {
   186→    res.status(400).json({ error: parsed.error.message });
   187→    return;
   188→  }
   189→
   190→  const { imageData, imageMediaType, platform, mapType, contextNotes, instructions, audience } = parsed.data;
   191→
   192→  const platformFormats: Record<string, string> = {
   193→    instagram: "Engaging caption optimized for Instagram. Use line breaks. Include 3–5 hashtags only if highly relevant.",
   194→    facebook: "Conversational and informative. Can be slightly longer than Instagram. Hashtags only if relevant.",
   195→    substack: "Short introductory paragraph suitable for a Substack newsletter post or note. No hashtags.",
   196→    x: "Concise, maximum 280 characters. Punchy. No hashtags unless essential.",
   197→    bluesky: "Similar to X but max 300 characters. Thoughtful and direct. Hashtags only if very relevant.",
   198→  };
   199→
   200→  const client = getClient();
   201→  const userPrompt = `Map type: ${mapType}
   202→
   203→Author's additional context: ${contextNotes || "None provided"}
   204→
   205→Generate a fresh, entirely different caption for ${platform.toUpperCase()}. Do not reuse phrasing from any previous version.
   206→
   207→Instructions: ${instructions}
   208→Audience: ${audience}
   209→Format: ${platformFormats[platform] || "Platform-appropriate format."}
   210→
   211→Return only the caption text, no explanation.`;
   212→
   213→  let response;
   214→  try {
   215→    response = await client.messages.create({
   216→      model: "claude-sonnet-4-6",
   217→      max_tokens: 1024,
   218→      system: SYSTEM_PROMPT,
   219→      messages: [
   220→        {
   221→          role: "user",
   222→          content: [
   223→            {
   224→              type: "image",
   225→              source: {
   226→                type: "base64",
   227→                media_type: imageMediaType as "image/jpeg" | "image/png" | "image/gif" | "image/webp",
   228→                data: imageData,
   229→              },
   230→            },
   231→            { type: "text", text: userPrompt },
   232→          ],
   233→        },
   234→      ],
   235→    });
   236→  } catch (e) {
   237→    console.error("[captions/rewrite] Anthropic API error:", e);
   238→    const message = e instanceof Error ? e.message : "Unknown error";
   239→    res.status(500).json({ error: "AI service error", detail: message });
   240→    return;
   241→  }
   242→
   243→  const textContent = response.content.find((c) => c.type === "text");
   244→  if (!textContent || textContent.type !== "text") {
   245→    res.status(500).json({ error: "No text response from AI" });
   246→    return;
   247→  }
   248→
   249→  res.json(RewriteCaptionResponse.parse({ caption: textContent.text.trim() }));
   250→});
